import mysql.connector
import os
import sys
import re


def validate_file_path(file_path):
    """Validate the file path to prevent path traversal and injection attacks."""
    # Resolve to absolute path
    abs_path = os.path.realpath(file_path)
    
    # Define allowed directories for file imports
    allowed_directories = [
        os.path.realpath('/var/data/imports'),
        os.path.realpath('/tmp/etl'),
        os.path.realpath(os.path.join(os.getcwd(), 'data')),
    ]
    
    # Check if the resolved path is within an allowed directory
    is_allowed = any(
        abs_path.startswith(allowed_dir + os.sep) or abs_path == allowed_dir
        for allowed_dir in allowed_directories
    )
    
    if not is_allowed:
        raise ValueError(
            f"File path '{abs_path}' is not within allowed directories: {allowed_directories}"
        )
    
    # Check that the file actually exists
    if not os.path.isfile(abs_path):
        raise FileNotFoundError(f"File not found: {abs_path}")
    
    # Check file extension
    allowed_extensions = {'.csv', '.tsv', '.txt', '.dat'}
    _, ext = os.path.splitext(abs_path)
    if ext.lower() not in allowed_extensions:
        raise ValueError(f"File extension '{ext}' not allowed. Allowed: {allowed_extensions}")
    
    # Reject any path containing suspicious characters that could enable SQL injection
    # Only allow alphanumeric, underscores, hyphens, dots, and path separators
    basename = os.path.basename(abs_path)
    if not re.match(r'^[\w\-. ]+$', basename):
        raise ValueError(f"Filename contains invalid characters: {basename}")
    
    return abs_path


def validate_table_name(table_name):
    """Validate table name to prevent SQL injection."""
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table_name):
        raise ValueError(f"Invalid table name: {table_name}")
    if len(table_name) > 64:
        raise ValueError("Table name too long (max 64 characters)")
    return table_name


def validate_database_name(db_name):
    """Validate database name to prevent SQL injection."""
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', db_name):
        raise ValueError(f"Invalid database name: {db_name}")
    if len(db_name) > 64:
        raise ValueError("Database name too long (max 64 characters)")
    return db_name


def get_db_connection(host, user, password, database, port=3306):
    """Create a MySQL connection with local_infile enabled."""
    try:
        validated_db = validate_database_name(database)
        connection = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=validated_db,
            port=port,
            allow_local_infile=True,
            connection_timeout=30,
        )
        
        # Verify local_infile is enabled on the server side
        cursor = connection.cursor()
        cursor.execute("SHOW GLOBAL VARIABLES LIKE 'local_infile'")
        result = cursor.fetchone()
        if result and result[1].upper() != 'ON':
            print("WARNING: local_infile is not enabled on the MySQL server.")
            print("Run: SET GLOBAL local_infile = 1; on the server.")
            cursor.close()
            connection.close()
            sys.exit(1)
        cursor.close()
        
        return connection
    except mysql.connector.Error as err:
        print(f"Database connection error: {err}")
        sys.exit(1)


def check_table_exists(connection, table_name):
    """Check if the target table exists in the database."""
    cursor = connection.cursor()
    validated_table = validate_table_name(table_name)
    cursor.execute(
        "SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = %s",
        (validated_table,)
    )
    result = cursor.fetchone()
    cursor.close()
    return result[0] > 0


def get_table_columns(connection, table_name):
    """Get column information for a table."""
    cursor = connection.cursor()
    validated_table = validate_table_name(table_name)
    cursor.execute(
        "SELECT column_name, data_type FROM information_schema.columns "
        "WHERE table_schema = DATABASE() AND table_name = %s ORDER BY ordinal_position",
        (validated_table,)
    )
    columns = cursor.fetchall()
    cursor.close()
    return columns


def build_load_data_query(file_path, table_name, delimiter=',', enclosed_by='"',
                          lines_terminated_by='\\n', ignore_lines=1, use_local=True,
                          columns=None):
    """
    Build a LOAD DATA INFILE query using parameterized components.
    
    Since LOAD DATA INFILE doesn't support parameter binding for file paths
    and table names, we validate all inputs strictly before constructing the query.
    """
    # Validate inputs
    validated_path = validate_file_path(file_path)
    validated_table = validate_table_name(table_name)
    
    # Validate delimiter
    allowed_delimiters = {',', '\t', '|', ';'}
    if delimiter not in allowed_delimiters:
        raise ValueError(f"Invalid delimiter. Allowed: {allowed_delimiters}")
    
    # Validate enclosed_by
    if enclosed_by not in {'"', "'", ''}:
        raise ValueError("Invalid enclosed_by character")
    
    # Validate ignore_lines
    if not isinstance(ignore_lines, int) or ignore_lines < 0:
        raise ValueError("ignore_lines must be a non-negative integer")
    
    # Escape the file path for MySQL (double backslashes for Windows paths)
    mysql_path = validated_path.replace('\\', '\\\\')
    
    local_keyword = "LOCAL " if use_local else ""
    
    # Use backtick quoting for the table name (already validated)
    query = f"""LOAD DATA {local_keyword}INFILE '{mysql_path}'
INTO TABLE `{validated_table}`
CHARACTER SET utf8mb4
FIELDS TERMINATED BY '{delimiter}'
OPTIONALLY ENCLOSED BY '{enclosed_by}'
LINES TERMINATED BY '{lines_terminated_by}'
IGNORE {ignore_lines} LINES"""
    
    # Add column specification if provided
    if columns:
        # Validate each column name
        validated_columns = []
        for col in columns:
            col = col.strip()
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', col):
                raise ValueError(f"Invalid column name: {col}")
            validated_columns.append(f"`{col}`")
        query += f"\n({', '.join(validated_columns)})"
    
    query += ";"
    return query


def execute_bulk_import(connection, file_path, table_name, delimiter=',',
                        enclosed_by='"', lines_terminated_by='\\n',
                        ignore_lines=1, use_local=True, columns=None):
    """Execute a LOAD DATA INFILE statement for bulk import."""
    cursor = None
    try:
        # Verify table exists
        if not check_table_exists(connection, table_name):
            raise ValueError(f"Table '{table_name}' does not exist in the database")
        
        # Show table structure
        table_columns = get_table_columns(connection, table_name)
        print(f"\nTarget table '{table_name}' columns:")
        for col_name, col_type in table_columns:
            print(f"  - {col_name} ({col_type})")
        
        # Build the query
        query = build_load_data_query(
            file_path=file_path,
            table_name=table_name,
            delimiter=delimiter,
            enclosed_by=enclosed_by,
            lines_terminated_by=lines_terminated_by,
            ignore_lines=ignore_lines,
            use_local=use_local,
            columns=columns,
        )
        
        print(f"\nExecuting query:\n{query}\n")
        
        cursor = connection.cursor()
        cursor.execute(query)
        connection.commit()
        
        rows_affected = cursor.rowcount
        warnings = cursor.fetchwarnings() if hasattr(cursor, 'fetchwarnings') else []
        
        print(f"Import completed successfully!")
        print(f"Rows imported: {rows_affected}")
        
        if warnings:
            print(f"\nWarnings ({len(warnings)}):")
            for warning in warnings[:10]:  # Show first 10 warnings
                print(f"  - {warning}")
            if len(warnings) > 10:
                print(f"  ... and {len(warnings) - 10} more warnings")
        
        return rows_affected
        
    except mysql.connector.Error as err:
        print(f"MySQL Error: {err}")
        if connection.is_connected():
            connection.rollback()
        raise
    except (ValueError, FileNotFoundError) as err:
        print(f"Validation Error: {err}")
        raise
    finally:
        if cursor:
            cursor.close()


