def run_batch_import(config_list, connection):
    """Run multiple imports from a list of configurations."""
    results = []
    for i, config in enumerate(config_list, 1):
        print(f"\n{'=' * 60}")
        print(f"Processing import {i}/{len(config_list)}")
        print(f"File: {config['file_path']} -> Table: {config['table_name']}")
